#include<bits/stdc++.h>
using namespace std;

int main()
{
	int a[101],n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	for(int i=1;i<=n;i++)
	{
       if(a[i]%10>=5)
       {
    		a[i]=a[i]+10-a[i]%10;
    		printf("%d\n",a[i]);
       }
       else
       {
       		a[i]=a[i]-a[i]%10;
       		printf("%d\n",a[i]);
       }
	}
	return 0;
}
